const express = require('express');
const crypto = require('crypto');

const app = express();
const port = process.env.PORT || 3000;

// Use express.raw to get the raw body for signature verification
app.post('/webhook', express.raw({ type: 'application/json' }), (req, res) => {
  const signature = req.headers['x-prembly-signature'];
  const secret = process.env.PREMBLY_API_KEY;

  if (!secret) {
    console.error('PREMBLY_API_KEY environment variable is not set');
    return res.status(500).json({ error: 'Internal server error' });
  }

  if (!signature) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  try {
    // Compute HMAC-SHA256 hash of the raw request body
    const computedSignature = crypto
      .createHmac('sha256', secret)
      .update(req.body)
      .digest('base64');

    // Securely compare the signatures
    // Note: crypto.timingSafeEqual requires Buffers of the same length.
    // Since we are comparing base64 strings, we can compare them directly or use timingSafeEqual on the buffers.
    const signatureBuffer = Buffer.from(signature);
    const computedBuffer = Buffer.from(computedSignature);

    if (signatureBuffer.length === computedBuffer.length && crypto.timingSafeEqual(signatureBuffer, computedBuffer)) {
      console.log('Webhook signature verified successfully');
      return res.status(200).json({ status: 'success' });
    } else {
      console.warn('Invalid webhook signature');
      return res.status(401).json({ error: 'Invalid signature' });
    }
  } catch (error) {
    console.error('Error verifying signature:', error);
    return res.status(401).json({ error: 'Invalid signature' });
  }
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

